SELECT p.sku, p.path, p.brand, p.series, p.model, p.name, i.available_today, p.properties
FROM products p
LEFT JOIN inventory i ON i.sku = p.sku AND i.store_id = 'store_innsbruck_wilten'
WHERE (
  p.brand = 'Heco' AND p.series = 'Heco Unix' AND p.model = 'HECO 2VD-VNA' AND p.name = 'Nut Bolt and Washer' AND p.properties LIKE '%"fastener_type":"bolt"%' AND p.properties LIKE '%"diameter_mm":12%' AND p.properties LIKE '%"length_mm":40%' AND p.properties LIKE '%"pack_count":100%'
) OR (
  p.brand = 'Helios' AND p.series = 'Helios Professional' AND p.model = 'Helios 29A-FTE' AND p.name = 'Metal and Concrete Paint' AND p.properties LIKE '%"product_type":"metal paint"%' AND p.properties LIKE '%"color_family":"White"%'
) OR (
  p.brand = 'Engelbert Strauss' AND p.series = 'Engelbert Strauss Classic' AND p.model = 'e.s. 37H-N9K' AND p.name = 'Work Trousers' AND (p.properties LIKE '%"color_family":"Blue"%' OR p.properties LIKE '%"color_family":"Black"%')
) OR (
  p.brand = 'Bahco' AND p.series = 'Bahco Workshop' AND p.model = 'BAH 3VZ-SPH' AND p.name = 'Hammer Measuring and Cutting Tool' AND p.properties LIKE '%"tool_type":"clamp"%'
) OR (
  p.brand = 'Sika' AND p.series = 'Sika Professional' AND p.model = 'Sika 28T-UV8' AND p.name = 'Sealant' AND p.properties LIKE '%"sealant_type":"hybrid sealant"%' AND p.properties LIKE '%"color_family":"Gray"%' AND p.properties LIKE '%"volume_ml":300%'
)
ORDER BY p.brand, p.model;

SELECT store_id, available_today
FROM inventory
WHERE sku = 'FST-1LWPDDC4' AND store_id IN ('store_graz_jakomini');
